import React from 'react'
import {useState} from 'react'

function App() {
  const [random_joke, setJoke] = useState("Click to Generate");
  function generate()
  {
    let arr = ["Dream big, Work hard","buri buri zymon"];
    let random = Math.floor(Math.random()*arr.length);

    setJoke(arr[random]);
  }

  return (
    <div style={{margin:"10px"}}>
    <h2>-- Random Quote Generator --</h2>
    <p>{random_joke}</p>
    <button onClick={generate}>Generate Random Joke</button>
    </div>
  )
}

export default App

